import{_ as o,c as r,o as e,ag as s}from"./chunks/framework.Co20b0ok.js";const n="/assets/image%2015._oVBIPgJ.png",g="/assets/image%2016.EdaENkiK.png",l="/assets/image%2017.CCmFV7RP.png",i="/assets/image%2018.B3EMd9A2.png",a="/assets/image%2019.X1QKtqaK.png",d="/assets/image%2020.DpsSyijo.png",c="/assets/image%2021.BELzWQ9o.png",_=JSON.parse('{"title":"Kerberos 委派","description":"","frontmatter":{},"headers":[],"relativePath":"study/domain/Kerberos 委派.md","filePath":"study/domain/Kerberos 委派.md"}'),S={name:"study/domain/Kerberos 委派.md"};function p(T,t,u,h,A,f){return e(),r("div",null,t[0]||(t[0]=[s('<h1 id="kerberos-委派" tabindex="-1">Kerberos 委派 <a class="header-anchor" href="#kerberos-委派" aria-label="Permalink to &quot;Kerberos 委派&quot;">​</a></h1><p>注：文章大部分由AI整理，以及下面的连接的资源，文章仅供作为理解使用。</p><p><a href="https://shenaniganslabs.io/2019/01/28/Wagging-the-Dog.html" target="_blank" rel="noreferrer">https://shenaniganslabs.io/2019/01/28/Wagging-the-Dog.html</a> 完全版</p><p>分两种：传统委派和资源委派</p><p>传统委派分为<strong>不受约束委派</strong>和<strong>受限委派</strong></p><table tabindex="0"><thead><tr><th><strong>类型</strong></th><th><strong>不受约束委派</strong></th><th><strong>受限委派（S4U2Proxy）</strong></th><th><strong>资源委派（RBCD）</strong></th></tr></thead><tbody><tr><td><strong>控制方式</strong></td><td>受信任的服务可委派到任何目标</td><td>只能委派到预定义的服务</td><td>目标服务决定谁可以委派</td></tr><tr><td><strong>配置方式</strong></td><td><code>TrustedForDelegation</code></td><td><code>msDS-AllowedToDelegateTo</code></td><td><code>msDS-AllowedToActOnBehalfOfOtherIdentity</code></td></tr><tr><td><strong>配置位置</strong></td><td><strong>委派方</strong>（Service A）</td><td><strong>委派方</strong>（Service A）</td><td><strong>目标服务</strong>（Service B）</td></tr><tr><td><strong>安全性</strong></td><td>低，可能被滥用</td><td>高，但仍需要管理员配置</td><td>最高，仅目标服务控制</td></tr><tr><td><strong>Windows 版本支持</strong></td><td>2000+</td><td>2003+</td><td>2012+</td></tr></tbody></table><h2 id="不受约束委派-trustedfordelegation" tabindex="-1">不受约束委派 <strong>TrustedForDelegation</strong> <a class="header-anchor" href="#不受约束委派-trustedfordelegation" aria-label="Permalink to &quot;不受约束委派 **TrustedForDelegation**&quot;">​</a></h2><p>如何设置非约束委派，将<code>server01</code>设置不受约束委派</p><p><img src="'+n+'" alt="image.png"></p><p>配置了非约束性委派属性的机器账号的<code>userAccountControl</code>属性有个Flag位 WORKSTATION_TRUST_ACCOUNT | TRUSTED_FOR_DELEGATION，其对应的数是0x81000=528384。</p><p>配置了非约束性委派属性的服务账号的<code>userAccountControl</code> 属性有个Flag位 NORMAL_ACCOUNT | TRUSTED_FOR_DELEGATION， 其对应的数是0x80200=524800。</p><p><img src="'+g+'" alt="image.png"></p><p><strong>用户发送 TGS以及他们的 TGT</strong>来访问服务，然后服务可以使用用户的 TGT 向任何其他服务请求该用户的 TGS 并模拟用户</p><p><img src="'+l+'" alt="image.png"></p><ul><li><strong>用户登录</strong>：用户向 KDC 申请 TGT（Ticket Granting Ticket）。</li><li><strong>用户访问 Web 服务</strong>：用户使用 TGT 申请 Web 服务器的 TGS，然后向 Web 服务器发送该 TGS。</li><li><strong>Web 服务器访问数据库</strong>： <ul><li>Web 服务器本身具有 <strong>TrustedForDelegation</strong> 标志。</li><li>Web 服务器接收到用户的 TGS 后，可以利用该票据向 KDC 申请用户访问数据库的 TGS。</li><li>Web 服务器拿着用户的数据库 TGS 访问数据库，数据库认为 Web 服务器就是用户本身。</li></ul></li></ul><p><strong>不受约束的委派（TrustedForDelegation）</strong> 使得 Web 服务器可以以用户的身份访问多个后端服务，而不是用自己的身份进行访问。</p><p>假如web服务器被攻破，那么用户权限将会被滥用。</p><h2 id="s4u2self-service-for-user-to-self" tabindex="-1">S4U2Self（Service for User to Self） <a class="header-anchor" href="#s4u2self-service-for-user-to-self" aria-label="Permalink to &quot;S4U2Self（Service for User to Self）&quot;">​</a></h2><p><strong>S4U2Self</strong> 是一种允许服务（如 Web 服务器）获取代表用户的 <strong>服务票证</strong> 的机制。在这个过程中，服务并不需要用户直接参与身份验证。它通过此扩展，服务可以代表某个用户获取其 Kerberos 票证，而无需用户自己去请求</p><ul><li><strong>S4U2Self</strong> 允许 <strong>服务</strong>（机器用户也算，而非用户）请求代表该用户的 <strong>服务票证</strong>（TGT, Ticket Granting Ticket）。</li><li>这对于一些情况下的委派非常有用，比如服务需要代表某个用户进行后端操作（例如数据库查询）但用户无法在这些服务之间进行直接身份验证时</li></ul><h2 id="s4u2proxy-service-for-user-to-proxy" tabindex="-1">S4U2Proxy（Service for User to Proxy） <a class="header-anchor" href="#s4u2proxy-service-for-user-to-proxy" aria-label="Permalink to &quot;S4U2Proxy（Service for User to Proxy）&quot;">​</a></h2><p><strong>S4U2Proxy</strong> 是扩展了 <strong>S4U2Self</strong> 的机制，允许 <strong>服务</strong> 不仅代表用户访问自身的资源，还可以 <strong>代表用户访问其他服务</strong>。这个扩展允许服务代理通过 <strong>服务票证</strong> 将用户的凭证传递到下游服务，以便在 <strong>多服务环境中</strong> 实现委派。</p><ul><li><strong>S4U2Proxy</strong> 允许服务将用户的凭证传递给其他 <strong>下游服务</strong>，使得下游服务能够以用户的身份进行身份验证。</li><li>这通常应用于 <strong>多层服务架构</strong>，如 Web 服务器访问数据库，数据库又需要访问其他资源的情况。</li></ul><h2 id="受限委派-s4u2proxy" tabindex="-1">受限委派 <strong>S4U2Proxy</strong> <a class="header-anchor" href="#受限委派-s4u2proxy" aria-label="Permalink to &quot;受限委派 **S4U2Proxy**&quot;">​</a></h2><p>受限委派（<strong>Constrained Delegation</strong>），即 <strong>S4U2Proxy（Service for User to Proxy）</strong>，是 Kerberos 允许服务 <strong>代表用户访问另一个服务</strong> 的一种方式。相比于不受约束的委派（TrustedForDelegation），受限委派增加了 <strong>安全限制</strong>，只能委派到 <strong>预定义的服务</strong>。</p><ol><li><p>由于非约束性委派的不安全性，微软在Windows Server 2003中发布了约束性委派。同时，为了在Kerberos协议层面对约束性委派的支持，微软扩展了两个子协议 S4u2Self(Service for User to Self) 和 S4u2Proxy (Service for User to Proxy )，这两个扩展都允许服务代表用户从KDC请求票证。</p><p><strong>S4U2self可以代表自身请求针对其自身的Kerberos服务票据(ST1)；S4U2proxy可以以用户的名义请求其它服务的ST2，约束委派就是限制了S4U2proxy扩展的范围</strong>, 只能模拟该用户访问特定的服务。</p></li><li><p>配置了约束性委派账户的msDS- AllowedToDelegateTo属性会指定对哪个SPN进行委派。约束委派的设置需要 SeEnableDelegation 特权，该特权通常仅授予域管理员。</p></li><li><p>配置了非约束性委派的机器账号的<code>userAccountControl</code>属性有个FLAG位 WORKSTATION_TRUST_ACCOUNT | TRUETED_TO_AUTHENTICATE_FOR_DELEGATION，其对应的数是0x1001000=16781312。</p></li><li><p>配置了非约束性委派的服务账号的<code>userAccountControl</code>属性有个FLAG位 NORMAL_ACCOUNT | TRUETED_TO_AUTHENTICATE_FOR_DELEGATION，其对应的数是0x1000200=16777728。</p></li></ol><p><img src="'+i+'" alt="image.png"></p><ul><li><strong>用户请求访问“服务 A”</strong>，并发送一个 <strong>TGS（用户 → 服务 A）</strong> 进行身份验证。</li><li><strong>服务 A 需要访问“服务 B”</strong>（如 Web 服务器需要访问数据库）。</li><li><strong>服务 A 调用 S4U2Proxy</strong>，使用 <strong>用户的 TGS（FORWARDABLE）</strong> 作为“证据”，向 KDC 申请 <strong>用户访问服务 B 的 TGS（用户 → 服务 B）</strong>。</li><li><strong>KDC 检查服务 A 是否被允许委派到服务 B</strong>（必须预先在 Active Directory 配置）。</li><li><strong>KDC 生成 TGS（用户 → 服务 B）并返回给服务 A</strong>。</li><li><strong>服务 A 使用该 TGS 代表用户访问服务 B</strong>。</li></ul><p>关键就是：用户提供的 TGS 必须设置 <code>FORWARDABLE</code> 标志。如果用户账号被标记为 <code>USER_NOT_DELEGATED = true</code> 或属于 <strong>受保护用户组</strong>，则 TGS <strong>不会</strong> 设置 FORWARDABLE，导致委派失败。所以，<strong>S4U2Proxy</strong> 需要用户的 TGS 作为“证据”才能代表用户访问其他服务</p><p>如何配置约束性委派</p><p>配置允许域计算机<code>SERVER01</code> 允许对 <code>WEB-SERVER</code> 上的 <strong>CIFS（共享文件服务）</strong> 进行委派， 表示 <code>SERVER01</code> 可以使用 Kerberos 票据代表用户访问 <code>WEB-SERVER</code> 上的 CIFS 共享</p><p><img src="'+a+'" alt="image.png"></p><h2 id="协议转换-s4u2self-trustedtoauthfordelegation" tabindex="-1"><strong>协议转换 (S4U2Self/TrustedToAuthForDelegation)</strong> <a class="header-anchor" href="#协议转换-s4u2self-trustedtoauthfordelegation" aria-label="Permalink to &quot;**协议转换 (S4U2Self/TrustedToAuthForDelegation)**&quot;">​</a></h2><p>协议转换（Protocol Transition）允许一个服务在没有用户 Kerberos 票据（TGS）的情况下，仍然能代表用户进行委派。这主要依赖 <strong>S4U2Self</strong> 和 <strong>S4U2Proxy</strong> 两个机制。</p><p><img src="'+d+'" alt="image.png"></p><ul><li><strong>用户访问 Web 服务器</strong>，但使用的是 NTLM、表单认证等非 Kerberos 方式，因此<strong>没有 TGS</strong>。</li><li><strong>Web 服务器调用 S4U2Self</strong>，请求 KDC 生成一个 <strong>用户 → Web 服务器</strong> 的 TGS（即用户的“伪造”票据）。</li><li><strong>Web 服务器拿到用户的 TGS</strong> 后，可以用它作为 S4U2Proxy 的“证据”。</li><li><strong>Web 服务器调用 S4U2Proxy</strong>，向 KDC 申请用户访问后端数据库的 TGS。</li><li><strong>Web 服务器使用这个新的 TGS 代表用户访问数据库</strong>。</li></ul><h3 id="为什么需要-trustedtoauthfordelegation" tabindex="-1">为什么需要 TrustedToAuthForDelegation ？ <a class="header-anchor" href="#为什么需要-trustedtoauthfordelegation" aria-label="Permalink to &quot;为什么需要 TrustedToAuthForDelegation ？&quot;">​</a></h3><p><strong>S4U2Self 允许服务“凭空”获取用户的 TGS</strong>，这意味着它可以伪造任何用户的身份，从而代表用户访问其他服务。因此，Active Directory 需要一种机制来控制哪些服务可以使用 S4U2Self。这就是 <code>TrustedToAuthForDelegation</code> 标志的作用。</p><p>只有<strong>带有</strong> <code>TrustedToAuthForDelegation</code> <strong>标志的服务账户</strong> 才能使用 S4U2Self 来获取用户的 TGS，否则 KDC 会拒绝该请求。这是为了防止所有服务都能随意伪造用户身份，提升安全性</p><p>所以：S4U2Self + S4U2Proxy = 无需用户提供 TGS 的委派</p><h2 id="资源委派-rbcd" tabindex="-1">资源委派 （RBCD） <a class="header-anchor" href="#资源委派-rbcd" aria-label="Permalink to &quot;资源委派 （RBCD）&quot;">​</a></h2><p>为了配置约束委派，必须拥有 <code>SeEnableDelegation</code> 权限，该权限非常敏感，通常只授予域管理员。为了赋予用户/资源更多独立性，Windows Server 2012 中引入了基于资源的约束委派。基于资源的约束委派允许资源配置哪些帐户值得信任并委派给他们。</p><p>这种约束委派与传统约束委派非常相似，但工作方向相反。</p><p>从账户 A 到账户 B 的<strong>传统约束委派</strong>是在账户 A 的 <code>msDS-AllowedToDelegateTo</code> 属性中配置的，并定义了从 A 到 B 的“传出”信任。</p><p>而<strong>基于资源的约束委派</strong>是在账户 B 的 <code>msDS-AllowedToActOnBehalfOfOtherIdentity</code> 属性中配置的，并定义了从 A 到 B 的“传入”信任。</p><p><img src="'+c+'" alt="image.png"></p><ul><li><strong>让目标服务（Service B）自己决定谁可以代表用户进行委派</strong>，而不是由服务 A 决定。</li><li>目标服务（Service B）在 Active Directory 中的 <code>msDS-AllowedToActOnBehalfOfOtherIdentity</code> 属性中 <strong>存储允许委派的服务（Service A）</strong>。</li></ul>',47)]))}const m=o(S,[["render",p]]);export{_ as __pageData,m as default};
